        <template slot-scope="scope">
          <el-input
            v-model="scope.row.cost_price"
            type="number"
            required
            min="0"
            size="mini"
            placeholder=""
          />
        </template>
      </el-table-column>
      <el-table-column label="市價">
        <template slot-scope="scope">
          <el-input
            v-model="scope.row.market_price"
            type="number"
            required
            min="0"
            size="mini"
            placeholder=""
          />
        </template>
      </el-table-column>
      <el-table-column label="條碼">
        <template slot-scope="scope">
