      <el-table-column width="80">
        <template slot-scope="scope">
          <el-button type="primary" size="mini" @click="onFillSpecItems"> 填充 </el-button>
        </template>
      </el-table-column>
    </el-table>

    <el-table :data="value.specItems" border style="line-height: initial; width: 100%">
      <el-table-column prop="spec_name" label="規格" />
      <el-table-column prop="item_id" label="狀態" :render-header="renderRequire">
        <template slot-scope="scope">
          <el-select v-model="scope.row.approve_status" size="mini" placeholder="請選擇">
            <el-option
              v-for="item in statusOption"
              :key="item.value"
              :label="item.title"
              :value="item.value"
              size="mini"
            />
          </el-select>
        </template>
      </el-table-column>
      <el-table-column prop="store" label="庫存" :render-header="renderRequire">
        <template slot-scope="scope">
          <el-input v-model="scope.row.store" type="number" min="0" size="mini" />
        </template>
      </el-table-column>
      <el-table-column prop="item_bn" label="貨號">
        <template slot-scope="scope">
          <el-input v-model="scope.row.item_bn" size="mini" />
        </template>
      </el-table-column>
      <el-table-column prop="weight" label="重量（kg）">
        <template slot-scope="scope">
          <el-input v-model="scope.row.weight" size="mini" />
        </template>
      </el-table-column>
      <el-table-column prop="volume" label="體積（m³）">
        <template slot-scope="scope">
