<style lang="scss"></style>
<template>
  <div>
    <!-- form: {{ form }} -->
    <SpForm ref="form" v-model="form" label-width="100px" :form-list="formList" :submit="false" />
  </div>
</template>

<script>
export default {
  name: 'SpecParams',
  props: {
    value: {
      type: Object,
      default: () => {}
    },
    isShowPoint: {
      type: Boolean,
      default: false
    }
  },
  data() {
    let statusOption = [
      {
        title: '前台可銷售',
        value: 'onsale'
      },
      {
        title: '前台僅顯示',
        value: 'only_show'
      },
      {
        title: '不可銷售',
        value: 'instock'
      }
    ]
    if (!this.VERSION_IN_PURCHASE) {
      statusOption.push({
        title: '前台不顯示',
        value: 'offline_sale'
      })
    }
    return {
      form: {
        approve_status: 'onsale',
        store: 1,
        item_bn: '',
        weight: '',
        volume: '',
        price: '',
        cost_price: '',
        market_price: '',
        barcode: '',
        point_num: 0
      },
      formList: [
        {
          label: '商品狀態',
          key: 'approve_status',
          type: 'select',
          options: statusOption,
          display: 'inline'
        },
        {
          label: '庫存',
          key: 'store',
          type: 'input',
          display: 'inline'
        },
        {
          label: '商品貨號',
          key: 'item_bn',
          type: 'input',
          display: 'inline'
        },
        {
          label: '重量',
          key: 'weight',
          type: 'input',
          display: 'inline'
        },
        {
          label: '體積',
          key: 'volume',
          type: 'input',
          display: 'inline'
        },
        {
          label: '售價',
          key: 'price',
          type: 'input',
          required: true,
          message: '請輸入商品售價',
          display: 'inline'
        },
        {
          label: '進價',
          key: 'cost_price',
          type: 'input',
          display: 'inline'
        },
        {
          label: '市價',
          key: 'market_price',
          type: 'input',
          display: 'inline'
        },
        {
          label: '條碼',
          key: 'barcode',
          type: 'input',
          display: 'inline'
        }
      ]
    }
  },
  watch: {
    value(newVal) {
      this.form = newVal
    },
    form: {
      deep: true,
      handler(newVal) {
        this.$emit('input', newVal)
      }
    },
    isShowPoint: {
      handler(newVal) {
        if (newVal) {
          this.formList.push({
            label: '獲取積分',
            key: 'point_num',
            type: 'input',
            display: 'inline'
          })
        }
      }
    }
  },
  methods: {
    async handleSubmit() {
      await this.$refs['form'].handleSubmit()
    }
  }
}
</script>
